function solution(input) {
  const words = input.split(' ');
  const map = {};
  for (const word of words) {
    const key = word.split('').sort().join('');
    if (!map[key]) map[key] = [];
    map[key].push(word);
  }
  return Object.values(map).map(g => g.join(' ')).join('\n');
}
